const response = $input.first().json;
const contacts = response.contacts || [];
const staticData = $getWorkflowStaticData('global');
staticData.allScores = [];
return contacts.map(c => ({ json: { id: c.id, firstName: c.firstName || '', lastName: c.lastName || '', email: c.email || '', phone: c.phone || '', tags: c.tags || [] } }));

const items = $input.all();
const ids = items.map(i => i.json.id).filter(Boolean);
const idList = ids.map(id => '"' + id + '"').join(',');
const url = 'https://xbxwvfnrqrjobalkmbeu.supabase.co/rest/v1/platinum_health_scores?contact_id=not.in.(' + idList + ')';
return [{ json: { cleanupUrl: url, currentIdCount: ids.length } }];

const batchItem = $('Loop Contacts').first().json;
const convResponse = $input.first().json;
const conversations = convResponse.conversations || [];
return [{
  json: {
    contactId: batchItem.id || '',
    contactName: ((batchItem.firstName || '') + ' ' + (batchItem.lastName || '')).trim() || 'Unknown',
    contactEmail: batchItem.email || '',
    contactPhone: batchItem.phone || '',
    contactTags: batchItem.tags || [],
    conversationId: conversations.length > 0 ? conversations[0].id : '',
    hasConversation: conversations.length > 0
  }
}];

const contact = $('Process Conversations').first().json;
const raw = $input.first().json;
const now = new Date();
const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

let msgArray = [];
if (raw && raw.messages && raw.messages.messages) {
  msgArray = raw.messages.messages;
}

const realMessages = msgArray.filter(m => m && ['TYPE_SMS', 'TYPE_EMAIL', 'TYPE_CALL'].includes(m.messageType));

const inboundMsgs = realMessages.filter(m => m.direction === 'inbound').sort((a, b) => new Date(b.dateAdded) - new Date(a.dateAdded));
const lastInbound = inboundMsgs.length > 0 ? new Date(inboundMsgs[0].dateAdded) : null;
const daysSinceInbound = lastInbound ? Math.floor((now - lastInbound) / (1000 * 60 * 60 * 24)) : -1;

const outboundMsgs = realMessages.filter(m => m.direction === 'outbound').sort((a, b) => new Date(b.dateAdded) - new Date(a.dateAdded));
const lastOutbound = outboundMsgs.length > 0 ? new Date(outboundMsgs[0].dateAdded) : null;
const daysSinceOutbound = lastOutbound ? Math.floor((now - lastOutbound) / (1000 * 60 * 60 * 24)) : -1;

const messagesLast30d = realMessages.filter(m => new Date(m.dateAdded) >= thirtyDaysAgo).length;

const hasActiveCampaign = (contact.contactTags || []).some(t => t === 'active ad');

let score = 0;
const dsi = daysSinceInbound === -1 ? 999 : daysSinceInbound;
const dso = daysSinceOutbound === -1 ? 999 : daysSinceOutbound;

if (dsi <= 7) score += 25; else if (dsi <= 14) score += 20; else if (dsi <= 30) score += 10;
if (dso <= 3) score += 15; else if (dso <= 7) score += 12; else if (dso <= 14) score += 8;
if (messagesLast30d >= 10) score += 20; else if (messagesLast30d >= 5) score += 15; else if (messagesLast30d >= 1) score += 10;
if (hasActiveCampaign) score += 20;
if (dsi <= 7) score += 20; else if (dsi <= 14) score += 15; else if (dsi <= 30) score += 10;

let tier = 'Critical';
if (score >= 80) tier = 'Healthy';
else if (score >= 60) tier = 'Monitor';
else if (score >= 40) tier = 'At Risk';

let recommendation = '';
if (tier === 'Critical') {
  if (daysSinceInbound === -1) recommendation = 'No conversation history. Call immediately to re-engage.';
  else if (!hasActiveCampaign) recommendation = 'No active campaign and ' + dsi + ' days since last contact. Schedule a call to discuss next campaign.';
  else recommendation = dsi + ' days since last message. Check in immediately.';
} else if (tier === 'At Risk') {
  if (!hasActiveCampaign) recommendation = 'No active campaign. Reach out to plan next ad campaign.';
  else recommendation = 'Engagement declining. Send a personal check-in message.';
} else if (tier === 'Monitor') {
  recommendation = 'Activity slowing. Keep an eye on engagement this week.';
} else {
  recommendation = 'Healthy - no action needed.';
}

return [{ json: {
  contact_id: contact.contactId,
  contact_name: contact.contactName,
  contact_email: contact.contactEmail,
  contact_phone: contact.contactPhone,
  health_score: score,
  health_tier: tier,
  days_since_inbound: daysSinceInbound,
  days_since_outbound: daysSinceOutbound,
  messages_last_30d: messagesLast30d,
  has_active_campaign: hasActiveCampaign,
  client_initiated_days: daysSinceInbound,
  ai_recommendation: recommendation
} }];

const data = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.allScores) staticData.allScores = [];
staticData.allScores.push({
  contact_name: data.contact_name,
  contact_email: data.contact_email,
  health_score: data.health_score,
  health_tier: data.health_tier,
  days_since_inbound: data.days_since_inbound,
  messages_last_30d: data.messages_last_30d,
  has_active_campaign: data.has_active_campaign
});
return [{ json: data }];

const staticData = $getWorkflowStaticData('global');
const allScores = staticData.allScores || [];
staticData.allScores = [];

const critical = allScores.filter(s => s.health_tier === 'Critical');
const atRisk = allScores.filter(s => s.health_tier === 'At Risk');
const monitor = allScores.filter(s => s.health_tier === 'Monitor');
const healthy = allScores.filter(s => s.health_tier === 'Healthy');

return [{ json: {
  totalClients: allScores.length,
  criticalCount: critical.length,
  atRiskCount: atRisk.length,
  monitorCount: monitor.length,
  healthyCount: healthy.length,
  criticalClients: critical,
  atRiskClients: atRisk,
  monitorClients: monitor,
  allScores: allScores
} }];

const data = $input.first().json;
const needsAttention = JSON.stringify({
  critical: data.criticalClients,
  atRisk: data.atRiskClients
}).substring(0, 8000);

const prompt = 'You are a client success analyst for GM Baptist Outreach, a church SaaS platform. Analyze these platinum client health scores and provide actionable recommendations.\n\nScoring: 0-39 Critical, 40-59 At Risk, 60-79 Monitor, 80-100 Healthy.\ndays_since_inbound = days since client last messaged us (-1 means never).\nmessages_last_30d = total messages in last 30 days.\nhas_active_campaign = whether they have a recent ad campaign.\n\nReturn JSON:\n{"executive_summary": "2-3 sentence overview of overall client health", "action_items": [{"name": "client name", "score": N, "tier": "...", "recommendation": "specific 1-sentence action to take"}], "trends": "1 sentence on what the data suggests about client retention"}\n\nTotal clients: ' + data.totalClients + '\nHealthy: ' + data.healthyCount + '\nMonitor: ' + data.monitorCount + '\nAt Risk: ' + data.atRiskCount + '\nCritical: ' + data.criticalCount + '\n\nClients needing attention:\n' + needsAttention;

return [{ json: {
  totalClients: data.totalClients,
  criticalCount: data.criticalCount,
  atRiskCount: data.atRiskCount,
  monitorCount: data.monitorCount,
  healthyCount: data.healthyCount,
  requestBody: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 2000,
    messages: [{ role: 'user', content: prompt }]
  }
} }];

const claudeResponse = $input.first().json;
const stats = $('Prepare Summary').first().json;
let report = {};
try {
  const text = claudeResponse.content[0].text;
  const match = text.match(/\{[\s\S]*\}/);
  if (match) report = JSON.parse(match[0]);
} catch (e) {
  report = { error: 'Failed to parse', raw: claudeResponse.content && claudeResponse.content[0] ? claudeResponse.content[0].text : '' };
}

return [{ json: {
  generatedAt: new Date().toISOString(),
  totalClients: stats.totalClients,
  healthy: stats.healthyCount,
  monitor: stats.monitorCount,
  atRisk: stats.atRiskCount,
  critical: stats.criticalCount,
  ...report
} }];
